import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';

const initialRegister = {
  email: '',
  phone: '',
  username: '',
  password: '',
  role: 'DONOR',
};

const initialLogin = {
  email: '',
  password: '',
};

function AuthPage() {
  const navigate = useNavigate();
  const { login, register, setFlash } = useAuth();

  const [mode, setMode] = useState('login');
  const [registerForm, setRegisterForm] = useState(initialRegister);
  const [loginForm, setLoginForm] = useState(initialLogin);
  const [busy, setBusy] = useState(false);

  async function handleRegister(event) {
    event.preventDefault();
    setBusy(true);
    try {
      await register(registerForm);
      navigate('/verify');
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setBusy(false);
    }
  }

  async function handleLogin(event) {
    event.preventDefault();
    setBusy(true);
    try {
      await login(loginForm);
      navigate('/dashboard');
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setBusy(false);
    }
  }

  return (
    <div className="auth-shell">
      <div className="panel auth-card">
        <h2>Portal Access</h2>
        <p>Sign in or register to start using the platform.</p>

        <div className="tab-row">
          <button className={mode === 'login' ? 'active' : ''} onClick={() => setMode('login')}>Login</button>
          <button className={mode === 'register' ? 'active' : ''} onClick={() => setMode('register')}>Register</button>
        </div>

        {mode === 'login' ? (
          <form onSubmit={handleLogin} className="form-grid single-col">
            <input
              type="email"
              placeholder="Email"
              value={loginForm.email}
              onChange={(e) => setLoginForm((prev) => ({ ...prev, email: e.target.value }))}
              required
            />
            <input
              type="password"
              placeholder="Password"
              value={loginForm.password}
              onChange={(e) => setLoginForm((prev) => ({ ...prev, password: e.target.value }))}
              required
            />
            <button type="submit" disabled={busy}>{busy ? 'Please wait...' : 'Login'}</button>
          </form>
        ) : (
          <form onSubmit={handleRegister} className="form-grid single-col">
            <input
              type="email"
              placeholder="Email"
              value={registerForm.email}
              onChange={(e) => setRegisterForm((prev) => ({ ...prev, email: e.target.value }))}
              required
            />
            <input
              placeholder="Phone"
              value={registerForm.phone}
              onChange={(e) => setRegisterForm((prev) => ({ ...prev, phone: e.target.value }))}
              required
            />
            <input
              placeholder="Username"
              value={registerForm.username}
              onChange={(e) => setRegisterForm((prev) => ({ ...prev, username: e.target.value }))}
              required
            />
            <input
              type="password"
              placeholder="Password"
              value={registerForm.password}
              onChange={(e) => setRegisterForm((prev) => ({ ...prev, password: e.target.value }))}
              required
            />
            <select
              value={registerForm.role}
              onChange={(e) => setRegisterForm((prev) => ({ ...prev, role: e.target.value }))}
            >
              <option value="DONOR">DONOR</option>
              <option value="RECIPIENT">RECIPIENT</option>
              <option value="ADMIN">ADMIN</option>
            </select>
            <button type="submit" disabled={busy}>{busy ? 'Please wait...' : 'Register'}</button>
          </form>
        )}
      </div>
    </div>
  );
}

export default AuthPage;
